import { useState, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Shield,
  Users,
  ChevronLeft,
  Loader2,
  CheckCircle2,
  Search,
  UserCheck,
  Lock,
  ArrowRight,
} from 'lucide-react';
import { roleService } from '@/api/auth/roleService';
import { permissionService } from '@/api/auth/permissionService';
import { userService } from '@/api/auth/userService';
import { useQuery } from '@tanstack/react-query';
import SheetGrid from "@/components/ui/grid/SheetGrid";
import { toast } from 'sonner';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { Button } from '@/shadcn/components/ui/button';
import { Tabs, TabsList, TabsTrigger } from '@/shadcn/components/ui/tabs';

export default function RoleConfiguration() {
  const { roleId } = useParams();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'users' | 'permissions'>('users');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [rolePerms, setRolePerms] = useState<Record<string, boolean>>({});
  const [searchQuery, setSearchQuery] = useState('');

  const { data: role, isLoading: roleLoading } = useQuery({
    queryKey: ['role', roleId],
    queryFn: () => roleService.getRoleById(roleId!),
    enabled: !!roleId
  });

  const { data: permissionGroups = [], isLoading: permsLoading } = useQuery({
    queryKey: ['permissionGroups'],
    queryFn: () => permissionService.getAllPermissionsGrouped(),
  });

  const { isLoading: initialPermsLoading } = useQuery({
    queryKey: ['rolePermissions', roleId],
    queryFn: async () => {
      const data = await roleService.getRolePermissions(roleId!);
      const permMap: Record<string, boolean> = {};
      if (data?.assignments) {
        data.assignments.forEach((a: any) => {
          permMap[a.permissionId] = a.isGranted;
        });
      }
      setRolePerms(permMap);
      return data;
    },
    enabled: !!roleId
  });

  const { data: allUsers = [], isLoading: usersLoading } = useQuery({
    queryKey: ['employees'],
    queryFn: () => userService.getEmployees(),
  });

  const usersInRole = useMemo(() => {
    if (!role) return [];
    let filtered = allUsers.filter((u: any) => u.role === role.name);
    if (searchQuery) {
      filtered = filtered.filter((u: any) =>
        u.fullName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        u.email?.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    return filtered;
  }, [allUsers, role, searchQuery]);

  const handleSavePermissions = async () => {
    setIsSubmitting(true);
    try {
      const assignments = Object.keys(rolePerms)
        .map(id => ({
          permissionId: id,
          isGranted: rolePerms[id]
        }));

      await roleService.setRolePermissions(roleId!, assignments);
      toast.success('Permissions updated successfully');
    } catch (err) {
      toast.error('Failed to update permissions');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (roleLoading) {
    return (
      <div className="flex h-[80vh] items-center justify-center">
        <Loader2 className="animate-spin text-primary" size={48} />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 space-y-8">

        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <button
              onClick={() => navigate('/roles')}
              className="p-2.5 bg-card border border-border rounded-xl hover:bg-muted transition-all shadow-sm group"
            >
              <ChevronLeft size={20} className="text-muted-foreground group-hover:-translate-x-1 transition-transform" />
            </button>
            <div>
              <div className="flex items-center gap-2">
                <Shield className="text-primary" size={24} />
                <h1 className="text-3xl font-bold text-foreground tracking-tight">Role Configuration</h1>
              </div>
              <div className="flex items-center gap-2 mt-1 px-1">
                <span className="text-primary text-sm font-bold uppercase tracking-wider">
                  {role?.name}
                </span>
                <span className="text-muted-foreground text-xs font-medium ml-2">— {role?.description?.replace(/<[^>]*>/g, '') || 'Manage access and assignments'}</span>
              </div>
            </div>
          </div>

          {activeTab === 'permissions' && (
            <PermissionGate permission={PERMISSIONS.RolePermission.Update} mode="disable">
              <Button onClick={handleSavePermissions} disabled={isSubmitting}>
                {isSubmitting ? <Loader2 className="animate-spin" size={16} /> : <CheckCircle2 size={16} />}
                Save Changes
              </Button>
            </PermissionGate>
          )}
        </div>

        <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as 'users' | 'permissions')}>
          <TabsList>
            <TabsTrigger value="users" className="flex items-center gap-2">
              <Users size={16} />
              Users In Role ({usersInRole.length})
            </TabsTrigger>
            <TabsTrigger value="permissions" className="flex items-center gap-2">
              <Lock size={16} />
              Permissions Matrix
            </TabsTrigger>
          </TabsList>
        </Tabs>

        <div className="animate-in fade-in duration-400">
          {activeTab === 'users' ? (
            <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden flex flex-col min-h-[600px] relative">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary to-primary/40" />
              <div className="p-6 border-b border-border flex flex-col sm:flex-row justify-between sm:items-center gap-4 bg-muted/30 mt-1">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-primary/10 text-primary rounded-lg">
                    <UserCheck size={18} />
                  </div>
                  <h2 className="text-lg font-bold text-foreground tracking-tight">Assigned Team Members</h2>
                </div>
                <div className="relative w-full sm:w-72">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                  <input
                    type="text"
                    placeholder="Search users..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 border border-border rounded-lg text-sm bg-background text-foreground focus:outline-none focus:ring-1 focus:ring-primary/30 focus:border-primary transition"
                  />
                </div>
              </div>

              <div className="p-6">
                {usersLoading ? (
                  <div className="flex justify-center py-24">
                    <Loader2 className="animate-spin text-primary/30" size={32} />
                  </div>
                ) : usersInRole.length === 0 ? (
                  <div className="py-24 flex flex-col items-center gap-4 text-muted-foreground/40">
                    <Users size={48} strokeWidth={1.5} />
                    <div className="text-center">
                      <p className="font-semibold text-foreground">No matching users found</p>
                      <p className="text-sm text-muted-foreground mt-1">Users must be assigned to this role in their profile</p>
                    </div>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                    {usersInRole.map((user: any) => (
                      <div key={user.id} className="group p-5 bg-card rounded-xl border border-border hover:border-primary/40 transition-all hover:shadow-md">
                        <div className="flex items-center gap-4">
                          <div className="w-11 h-11 rounded-lg bg-muted flex items-center justify-center text-foreground text-sm font-bold border border-border group-hover:bg-primary group-hover:text-primary-foreground group-hover:border-primary transition-colors">
                            {user.fullName?.charAt(0) || user.email?.charAt(0).toUpperCase()}
                          </div>
                          <div className="flex flex-col min-w-0">
                            <span className="text-sm font-bold text-foreground truncate">{user.fullName || 'Unnamed User'}</span>
                            <span className="text-[11px] font-medium text-muted-foreground truncate">{user.email}</span>
                          </div>
                        </div>
                        <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
                          <span className="text-[10px] font-mono font-medium text-muted-foreground">ID: {user.id?.slice(0, 8)}</span>
                          <button
                            onClick={() => navigate(`/users`)}
                            className="text-primary hover:text-primary/80 font-bold text-[11px] flex items-center gap-1 transition-colors"
                          >
                            Profile <ArrowRight size={12} />
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ) : (
            <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden flex flex-col min-h-[700px] relative">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary to-primary/40" />
              <div className="p-6 border-b border-border flex flex-col sm:flex-row justify-between sm:items-center gap-4 bg-muted/30 mt-1">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-primary/10 text-primary rounded-lg">
                    <Lock size={18} />
                  </div>
                  <h2 className="text-lg font-bold text-foreground tracking-tight">Access Control Matrix</h2>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mr-2">Quick Actions:</span>
                  <PermissionGate permission={PERMISSIONS.RolePermission.Update} mode="disable">
                    <button
                      onClick={() => {
                        const newPerms: Record<string, boolean> = {};
                        permissionGroups.forEach((g: any) => g.permissions.forEach((p: any) => newPerms[p.id] = true));
                        setRolePerms(newPerms);
                      }}
                      className="px-4 py-1.5 bg-muted hover:bg-muted/80 text-foreground rounded-md text-[11px] font-bold transition-all uppercase tracking-tight"
                    >
                      Select All
                    </button>
                  </PermissionGate>
                  <PermissionGate permission={PERMISSIONS.RolePermission.Update} mode="disable">
                    <button
                      onClick={() => setRolePerms({})}
                      className="px-4 py-1.5 bg-muted hover:bg-muted/80 text-foreground rounded-md text-[11px] font-bold transition-all uppercase tracking-tight"
                    >
                      Clear All
                    </button>
                  </PermissionGate>
                </div>
              </div>

              <div className="flex-1 p-6">
                {(permsLoading || initialPermsLoading) ? (
                  <div className="flex flex-col items-center justify-center py-40 gap-3">
                    <Loader2 className="animate-spin text-primary" size={32} />
                    <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Loading matrix data...</p>
                  </div>
                ) : (
                  <div className="h-[600px] border border-border rounded-xl overflow-hidden">
                    <SheetGrid
                      title="Interactive Access Grid"
                      data={permissionGroups.flatMap((g: any) => g.permissions.map((p: any) => ({
                        ...p,
                        resource: g.resource,
                        id: p.id
                      })))}
                      enableSelection={true}
                      selectedRows={new Set(Object.keys(rolePerms).filter(id => rolePerms[id]))}
                      onSelectedRowsChange={(newSelection) => {
                        const newPerms: Record<string, boolean> = {};
                        permissionGroups.forEach((g: any) => {
                          g.permissions.forEach((p: any) => {
                            newPerms[p.id] = newSelection.has(p.id);
                          });
                        });
                        setRolePerms(newPerms);
                      }}
                      customColumns={[
                        { key: 'displayName', name: 'Permission Name', minWidth: 200 },
                        { key: 'resource', name: 'Module Namespace', width: 220 },
                        { key: 'description', name: 'Business Logic Description', minWidth: 400 },
                        { key: 'action', name: 'Action', width: 100 }
                      ]}
                      pageSize={200}
                    />
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
